#include <pypilot_pilots_logic/pilots_logic.hpp>
#include <pypilot_pilots_logic/math_helpers.hpp>
#include <pypilot_pilots_logic/pilot_select.hpp>
namespace pypilot_pilots_logic { PilotsLogic::PilotsLogic():last_error_(""){} bool PilotsLogic::update_inputs(DataModel& model,uint64_t now_us){ last_error_=""; if(model.imu.heading_lowpass_deg.valid && model.ap.heading_command_deg.valid){ model.ap.heading_deg.set(model.imu.heading_lowpass_deg.value,now_us); model.ap.heading_error_deg.set(wrap_180(model.ap.heading_command_deg.value-model.imu.heading_lowpass_deg.value),now_us);} return true;} bool PilotsLogic::compute_command(DataModel& model,uint64_t now_us){ last_error_=""; if(!model.ap.enabled.value){ model.servo.command_norm.set_internal_command(0,now_us); return true; } PilotResult r=compute_selected_pilot(model,now_us); if(!r.valid){last_error_="pilot command invalid"; return false;} return true;} bool PilotsLogic::step(DataModel& model,uint64_t now_us){ return update_inputs(model,now_us)&&compute_command(model,now_us);} const char* PilotsLogic::last_error() const { return last_error_; } }
